2481 void VPWidenGEPRecipe::execute(VPTransformState &State) {
2482   assert(State.VF.isVector() && "not widening");
2483   // Construct a vector GEP by widening the operands of the scalar GEP as
2484   // necessary. We mark the vector GEP 'inbounds' if appropriate. A GEP
2485   // results in a vector of pointers when at least one operand of the GEP
2486   // is vector-typed. Thus, to keep the representation compact, we only use
2487   // vector-typed operands for loop-varying values.
2488 
2489   bool AllOperandsAreInvariant = all_of(operands(), [](VPValue *Op) {
2490     return Op->isDefinedOutsideLoopRegions();
2491   });
2492   if (AllOperandsAreInvariant) {
2493     // If we are vectorizing, but the GEP has only loop-invariant operands,
2494     // the GEP we build (by only using vector-typed operands for
2495     // loop-varying values) would be a scalar pointer. Thus, to ensure we
2496     // produce a vector of pointers, we need to either arbitrarily pick an
2497     // operand to broadcast, or broadcast a clone of the original GEP.
2498     // Here, we broadcast a clone of the original.
2499 
2500     SmallVector<Value *> Ops;
2501     for (unsigned I = 0, E = getNumOperands(); I != E; I++)
2502       Ops.push_back(State.get(getOperand(I), VPLane(0)));
2503 
2504     auto *NewGEP =
2505         State.Builder.CreateGEP(getSourceElementType(), Ops[0], drop_begin(Ops),
2506                                 "", getGEPNoWrapFlags());
2507     Value *Splat = State.Builder.CreateVectorSplat(State.VF, NewGEP);
2508     State.set(this, Splat);
2509     return;
2510   }
2511 
2512   // If the GEP has at least one loop-varying operand, we are sure to
2513   // produce a vector of pointers unless VF is scalar.
2514   // The pointer operand of the new GEP. If it's loop-invariant, we
2515   // won't broadcast it.
2516   auto *Ptr = State.get(getOperand(0), isPointerLoopInvariant());
2517 
2518   // Collect all the indices for the new GEP. If any index is
2519   // loop-invariant, we won't broadcast it.
2520   SmallVector<Value *, 4> Indices;
2521   for (unsigned I = 1, E = getNumOperands(); I < E; I++) {
2522     VPValue *Operand = getOperand(I);
2523     Indices.push_back(State.get(Operand, isIndexLoopInvariant(I - 1)));
2524   }
2525 
2526   // Create the new GEP. Note that this GEP may be a scalar if VF == 1,
2527   // but it should be a vector, otherwise.
2528   auto *NewGEP = State.Builder.CreateGEP(getSourceElementType(), Ptr, Indices,
2529                                          "", getGEPNoWrapFlags());
2530   assert((State.VF.isScalar() || NewGEP->getType()->isVectorTy()) &&
2531          "NewGEP is not a pointer vector");
2532   State.set(this, NewGEP);
2533 }
