2551 void VPVectorEndPointerRecipe::execute(VPTransformState &State) {
2552   auto &Builder = State.Builder;
2553   unsigned CurrentPart = getUnrollPart(*this);
2554   const DataLayout &DL = Builder.GetInsertBlock()->getDataLayout();
2555   Type *IndexTy = DL.getIndexType(State.TypeAnalysis.inferScalarType(this));
2556 
2557   // The wide store needs to start at the last vector element.
2558   Value *RunTimeVF = State.get(getVFValue(), VPLane(0));
2559   if (IndexTy != RunTimeVF->getType())
2560     RunTimeVF = Builder.CreateZExtOrTrunc(RunTimeVF, IndexTy);
2561   // NumElt = Stride * CurrentPart * RunTimeVF
2562   Value *NumElt = Builder.CreateMul(
2563       ConstantInt::getSigned(IndexTy, Stride * (int64_t)CurrentPart),
2564       RunTimeVF);
2565   // LastLane = Stride * (RunTimeVF - 1)
2566   Value *LastLane = Builder.CreateSub(RunTimeVF, ConstantInt::get(IndexTy, 1));
2567   if (Stride != 1)
2568     LastLane =
2569         Builder.CreateMul(ConstantInt::getSigned(IndexTy, Stride), LastLane);
2570   Value *Ptr = State.get(getOperand(0), VPLane(0));
2571   Value *ResultPtr =
2572       Builder.CreateGEP(IndexedTy, Ptr, NumElt, "", getGEPNoWrapFlags());
2573   ResultPtr = Builder.CreateGEP(IndexedTy, ResultPtr, LastLane, "",
2574                                 getGEPNoWrapFlags());
2575 
2576   State.set(this, ResultPtr, /*IsScalar*/ true);
2577 }
