2612 InstructionCost VPBlendRecipe::computeCost(ElementCount VF,
2613                                            VPCostContext &Ctx) const {
2614   // A blend will be expanded to a select VPInstruction, which will generate a
2615   // scalar select if only the first lane is used.
2616   if (vputils::onlyFirstLaneUsed(this))
2617     VF = ElementCount::getFixed(1);
