1571 static void narrowToSingleScalarRecipes(VPlan &Plan) {
1572   if (Plan.hasScalarVFOnly())
1573     return;
1574 
1575   // Try to narrow wide and replicating recipes to single scalar recipes,
1576   // based on VPlan analysis. Only process blocks in the loop region for now,
1577   // without traversing into nested regions, as recipes in replicate regions
1578   // cannot be converted yet.
1579   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
1580            vp_depth_first_shallow(Plan.getVectorLoopRegion()->getEntry()))) {
1581     for (VPRecipeBase &R : make_early_inc_range(reverse(*VPBB))) {
1582       if (!isa<VPWidenRecipe, VPWidenGEPRecipe, VPReplicateRecipe,
1583                VPWidenStoreRecipe>(&R))
1584         continue;
1585       auto *RepR = dyn_cast<VPReplicateRecipe>(&R);
1586       if (RepR && (RepR->isSingleScalar() || RepR->isPredicated()))
1587         continue;
1588 
1589       // Convert an unmasked scatter with an uniform address into
1590       // extract-last-lane + scalar store.
1591       // TODO: Add a profitability check comparing the cost of a scatter vs.
1592       // extract + scalar store.
1593       auto *WidenStoreR = dyn_cast<VPWidenStoreRecipe>(&R);
1594       if (WidenStoreR && vputils::isSingleScalar(WidenStoreR->getAddr()) &&
1595           !WidenStoreR->isConsecutive()) {
1596         assert(!WidenStoreR->isReverse() &&
1597                "Not consecutive memory recipes shouldn't be reversed");
1598         VPValue *Mask = WidenStoreR->getMask();
1599 
1600         // Only convert the scatter to a scalar store if it is unmasked.
1601         // TODO: Support converting scatter masked by the header mask to scalar
1602         // store.
1603         if (Mask)
1604           continue;
1605 
1606         auto *Extract = new VPInstruction(VPInstruction::ExtractLastLane,
1607                                           {WidenStoreR->getOperand(1)});
1608         Extract->insertBefore(WidenStoreR);
1609 
1610         // TODO: Sink the scalar store recipe to middle block if possible.
1611         auto *ScalarStore = new VPReplicateRecipe(
1612             &WidenStoreR->getIngredient(), {Extract, WidenStoreR->getAddr()},
1613             true /*IsSingleScalar*/, nullptr /*Mask*/, {},
1614             *WidenStoreR /*Metadata*/);
1615         ScalarStore->insertBefore(WidenStoreR);
1616         WidenStoreR->eraseFromParent();
1617         continue;
1618       }
1619 
1620       auto *RepOrWidenR = dyn_cast<VPRecipeWithIRFlags>(&R);
1621       if (RepR && isa<StoreInst>(RepR->getUnderlyingInstr()) &&
1622           vputils::isSingleScalar(RepR->getOperand(1))) {
1623         auto *Clone = new VPReplicateRecipe(
1624             RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1625             true /*IsSingleScalar*/, nullptr /*Mask*/, *RepR /*Flags*/,
1626             *RepR /*Metadata*/, RepR->getDebugLoc());
1627         Clone->insertBefore(RepOrWidenR);
1628         VPBuilder Builder(Clone);
1629         VPValue *ExtractOp = Clone->getOperand(0);
1630         if (vputils::isUniformAcrossVFsAndUFs(RepR->getOperand(1)))
1631           ExtractOp =
1632               Builder.createNaryOp(VPInstruction::ExtractLastPart, ExtractOp);
1633         ExtractOp =
1634             Builder.createNaryOp(VPInstruction::ExtractLastLane, ExtractOp);
1635         Clone->setOperand(0, ExtractOp);
1636         RepR->eraseFromParent();
1637         continue;
1638       }
1639 
1640       // Skip recipes that aren't single scalars.
1641       if (!RepOrWidenR || !vputils::isSingleScalar(RepOrWidenR))
1642         continue;
1643 
1644       // Skip recipes for which conversion to single-scalar does introduce
1645       // additional broadcasts. No extra broadcasts are needed, if either only
1646       // the scalars of the recipe are used, or at least one of the operands
1647       // would require a broadcast. In the latter case, the single-scalar may
1648       // need to be broadcasted, but another broadcast is removed.
1649       if (!all_of(RepOrWidenR->users(),
1650                   [RepOrWidenR](const VPUser *U) {
1651                     if (auto *VPI = dyn_cast<VPInstruction>(U)) {
1652                       unsigned Opcode = VPI->getOpcode();
1653                       if (Opcode == VPInstruction::ExtractLastLane ||
1654                           Opcode == VPInstruction::ExtractLastPart ||
1655                           Opcode == VPInstruction::ExtractPenultimateElement)
1656                         return true;
1657                     }
1658 
1659                     return U->usesScalars(RepOrWidenR);
1660                   }) &&
1661           none_of(RepOrWidenR->operands(), [RepOrWidenR](VPValue *Op) {
1662             if (Op->getSingleUser() != RepOrWidenR)
1663               return false;
1664             // Non-constant live-ins require broadcasts, while constants do not
1665             // need explicit broadcasts.
1666             bool LiveInNeedsBroadcast =
1667                 Op->isLiveIn() && !isa<Constant>(Op->getLiveInIRValue());
1668             auto *OpR = dyn_cast<VPReplicateRecipe>(Op);
1669             return LiveInNeedsBroadcast || (OpR && OpR->isSingleScalar());
1670           }))
1671         continue;
1672 
1673       auto *Clone = new VPReplicateRecipe(
1674           RepOrWidenR->getUnderlyingInstr(), RepOrWidenR->operands(),
1675           true /*IsSingleScalar*/, nullptr, *RepOrWidenR);
1676       Clone->insertBefore(RepOrWidenR);
1677       RepOrWidenR->replaceAllUsesWith(Clone);
1678       if (isDeadRecipe(*RepOrWidenR))
1679         RepOrWidenR->eraseFromParent();
1680     }
1681   }
1682 }
