1684 /// Try to see if all of \p Blend's masks share a common value logically and'ed
1685 /// and remove it from the masks.
1686 static void removeCommonBlendMask(VPBlendRecipe *Blend) {
1687   if (Blend->isNormalized())
1688     return;
1689   VPValue *CommonEdgeMask;
1690   if (!match(Blend->getMask(0),
1691              m_LogicalAnd(m_VPValue(CommonEdgeMask), m_VPValue())))
1692     return;
1693   for (unsigned I = 0; I < Blend->getNumIncomingValues(); I++)
1694     if (!match(Blend->getMask(I),
1695                m_LogicalAnd(m_Specific(CommonEdgeMask), m_VPValue())))
1696       return;
1697   for (unsigned I = 0; I < Blend->getNumIncomingValues(); I++)
1698     Blend->setMask(I, Blend->getMask(I)->getDefiningRecipe()->getOperand(1));
1699 }
