277 bool vputils::isSingleScalar(const VPValue *VPV) {
278   // A live-in must be uniform across the scope of VPlan.
279   if (VPV->isLiveIn())
280     return true;
281 
282   if (auto *Rep = dyn_cast<VPReplicateRecipe>(VPV)) {
283     const VPRegionBlock *RegionOfR = Rep->getRegion();
284     // Don't consider recipes in replicate regions as uniform yet; their first
285     // lane cannot be accessed when executing the replicate region for other
286     // lanes.
287     if (RegionOfR && RegionOfR->isReplicator())
288       return false;
289     return Rep->isSingleScalar() || (preservesUniformity(Rep->getOpcode()) &&
290                                      all_of(Rep->operands(), isSingleScalar));
291   }
292   if (isa<VPWidenGEPRecipe, VPDerivedIVRecipe, VPBlendRecipe>(VPV))
293     return all_of(VPV->getDefiningRecipe()->operands(), isSingleScalar);
294   if (auto *WidenR = dyn_cast<VPWidenRecipe>(VPV)) {
295     return preservesUniformity(WidenR->getOpcode()) &&
296            all_of(WidenR->operands(), isSingleScalar);
297   }
298   if (auto *VPI = dyn_cast<VPInstruction>(VPV))
299     return VPI->isSingleScalar() || VPI->isVectorToScalar() ||
300            (preservesUniformity(VPI->getOpcode()) &&
301             all_of(VPI->operands(), isSingleScalar));
302   if (auto *RR = dyn_cast<VPReductionRecipe>(VPV))
303     return !RR->isPartialReduction();
304   if (isa<VPCanonicalIVPHIRecipe, VPVectorPointerRecipe,
305           VPVectorEndPointerRecipe>(VPV))
306     return true;
307   if (auto *Expr = dyn_cast<VPExpressionRecipe>(VPV))
308     return Expr->isSingleScalar();
309 
310   // VPExpandSCEVRecipes must be placed in the entry and are always uniform.
311   return isa<VPExpandSCEVRecipe>(VPV);
312 }
