314 bool vputils::isUniformAcrossVFsAndUFs(VPValue *V) {
315   // Live-ins are uniform.
316   if (V->isLiveIn())
317     return true;
318 
319   VPRecipeBase *R = V->getDefiningRecipe();
320   if (R && V->isDefinedOutsideLoopRegions()) {
321     if (match(V->getDefiningRecipe(),
322               m_VPInstruction<VPInstruction::CanonicalIVIncrementForPart>()))
323       return false;
324     return all_of(R->operands(), isUniformAcrossVFsAndUFs);
325   }
326 
327   auto *CanonicalIV =
328       R->getParent()->getEnclosingLoopRegion()->getCanonicalIV();
329   // Canonical IV chain is uniform.
330   if (V == CanonicalIV || V == CanonicalIV->getBackedgeValue())
331     return true;
332 
333   return TypeSwitch<const VPRecipeBase *, bool>(R)
334       .Case<VPDerivedIVRecipe>([](const auto *R) { return true; })
335       .Case<VPReplicateRecipe>([](const auto *R) {
336         // Be conservative about side-effects, except for the
337         // known-side-effecting assumes and stores, which we know will be
338         // uniform.
339         return R->isSingleScalar() &&
340                (!R->mayHaveSideEffects() ||
341                 isa<AssumeInst, StoreInst>(R->getUnderlyingInstr())) &&
342                all_of(R->operands(), isUniformAcrossVFsAndUFs);
343       })
344       .Case<VPWidenRecipe>([](const auto *R) {
345         return preservesUniformity(R->getOpcode()) &&
346                all_of(R->operands(), isUniformAcrossVFsAndUFs);
347       })
348       .Case<VPInstruction>([](const auto *VPI) {
349         return (VPI->isScalarCast() &&
350                 isUniformAcrossVFsAndUFs(VPI->getOperand(0))) ||
351                (preservesUniformity(VPI->getOpcode()) &&
352                 all_of(VPI->operands(), isUniformAcrossVFsAndUFs));
353       })
354       .Case<VPWidenCastRecipe>([](const auto *R) {
355         // A cast is uniform according to its operand.
356         return isUniformAcrossVFsAndUFs(R->getOperand(0));
357       })
358       .Default([](const VPRecipeBase *) { // A value is considered non-uniform
359                                           // unless proven otherwise.
360         return false;
361       });
362 }
