388 std::optional<VPValue *>
389 vputils::getRecipesForUncountableExit(VPlan &Plan,
390                                       SmallVectorImpl<VPRecipeBase *> &Recipes,
391                                       SmallVectorImpl<VPRecipeBase *> &GEPs) {
392   // Given a VPlan like the following (just including the recipes contributing
393   // to loop control exiting here, not the actual work), we're looking to match
394   // the recipes contributing to the uncountable exit condition comparison
395   // (here, vp<%4>) back to either live-ins or the address nodes for the load
396   // used as part of the uncountable exit comparison so that we can copy them
397   // to a preheader and rotate the address in the loop to the next vector
398   // iteration.
399   //
400   // Currently, the address of the load is restricted to a GEP with 2 operands
401   // and a live-in base address. This constraint may be relaxed later.
402   //
403   // VPlan ' for UF>=1' {
404   // Live-in vp<%0> = VF
405   // Live-in ir<64> = original trip-count
406   //
407   // entry:
408   // Successor(s): preheader, vector.ph
409   //
410   // vector.ph:
411   // Successor(s): vector loop
412   //
413   // <x1> vector loop: {
414   //   vector.body:
415   //     EMIT vp<%2> = CANONICAL-INDUCTION ir<0>
416   //     vp<%3> = SCALAR-STEPS vp<%2>, ir<1>, vp<%0>
417   //     CLONE ir<%ee.addr> = getelementptr ir<0>, vp<%3>
418   //     WIDEN ir<%ee.load> = load ir<%ee.addr>
419   //     WIDEN vp<%4> = icmp eq ir<%ee.load>, ir<0>
420   //     EMIT vp<%5> = any-of vp<%4>
421   //     EMIT vp<%6> = add vp<%2>, vp<%0>
422   //     EMIT vp<%7> = icmp eq vp<%6>, ir<64>
423   //     EMIT branch-on-two-conds vp<%5>, vp<%7>
424   //   No successors
425   // }
426   // Successor(s): early.exit, middle.block
427   //
428   // middle.block:
429   // Successor(s): preheader
430   //
431   // preheader:
432   // No successors
433   // }
434 
435   // Find the uncountable loop exit condition.
436   auto *Region = Plan.getVectorLoopRegion();
437   VPValue *UncountableCondition = nullptr;
438   if (!match(Region->getExitingBasicBlock()->getTerminator(),
439              m_BranchOnTwoConds(m_AnyOf(m_VPValue(UncountableCondition)),
440                                 m_VPValue())))
441     return std::nullopt;
442 
443   SmallVector<VPValue *, 4> Worklist;
444   Worklist.push_back(UncountableCondition);
445   while (!Worklist.empty()) {
446     VPValue *V = Worklist.pop_back_val();
447 
448     // Any value defined outside the loop does not need to be copied.
449     if (V->isDefinedOutsideLoopRegions())
450       continue;
451 
452     // FIXME: Remove the single user restriction; it's here because we're
453     //        starting with the simplest set of loops we can, and multiple
454     //        users means needing to add PHI nodes in the transform.
455     if (V->getNumUsers() > 1)
456       return std::nullopt;
457 
458     VPValue *Op1, *Op2;
459     // Walk back through recipes until we find at least one load from memory.
460     if (match(V, m_ICmp(m_VPValue(Op1), m_VPValue(Op2)))) {
461       Worklist.push_back(Op1);
462       Worklist.push_back(Op2);
463       Recipes.push_back(V->getDefiningRecipe());
464     } else if (auto *Load = dyn_cast<VPWidenLoadRecipe>(V)) {
465       // Reject masked loads for the time being; they make the exit condition
466       // more complex.
467       if (Load->isMasked())
468         return std::nullopt;
469 
470       VPValue *GEP = Load->getAddr();
471       if (!match(GEP, m_GetElementPtr(m_LiveIn(), m_VPValue())))
472         return std::nullopt;
473 
474       Recipes.push_back(Load);
475       Recipes.push_back(GEP->getDefiningRecipe());
476       GEPs.push_back(GEP->getDefiningRecipe());
477     } else
478       return std::nullopt;
479   }
480 
481   return UncountableCondition;
482 }
