484 bool VPBlockUtils::isHeader(const VPBlockBase *VPB,
485                             const VPDominatorTree &VPDT) {
486   auto *VPBB = dyn_cast<VPBasicBlock>(VPB);
487   if (!VPBB)
488     return false;
489 
490   // If VPBB is in a region R, VPBB is a loop header if R is a loop region with
491   // VPBB as its entry, i.e., free of predecessors.
492   if (auto *R = VPBB->getParent())
493     return !R->isReplicator() && !VPBB->hasPredecessors();
494 
495   // A header dominates its second predecessor (the latch), with the other
496   // predecessor being the preheader
497   return VPB->getPredecessors().size() == 2 &&
498          VPDT.dominates(VPB, VPB->getPredecessors()[1]);
499 }
