501 bool VPBlockUtils::isLatch(const VPBlockBase *VPB,
502                            const VPDominatorTree &VPDT) {
503   // A latch has a header as its second successor, with its other successor
504   // leaving the loop. A preheader OTOH has a header as its first (and only)
505   // successor.
506   return VPB->getNumSuccessors() == 2 &&
507          VPBlockUtils::isHeader(VPB->getSuccessors()[1], VPDT);
508 }
