2686 // The function adds the following recipes:
2687 //
2688 // vector.ph:
2689 //   %TripCount = calculate-trip-count-minus-VF (original TC)
2690 //       [if DataWithControlFlowWithoutRuntimeCheck]
2691 //   %EntryInc = canonical-iv-increment-for-part %StartV
2692 //   %EntryALM = active-lane-mask %EntryInc, %TripCount
2693 //
2694 // vector.body:
2695 //   ...
2696 //   %P = active-lane-mask-phi [ %EntryALM, %vector.ph ], [ %ALM, %vector.body ]
2697 //   ...
2698 //   %InLoopInc = canonical-iv-increment-for-part %IncrementValue
2699 //   %ALM = active-lane-mask %InLoopInc, TripCount
2700 //   %Negated = Not %ALM
2701 //   branch-on-cond %Negated
2702 //
