2790       LoopRegion->getCanonicalIV()->users().end()) {
2791     auto *WideCanonicalIV =
2792         cast<VPWidenCanonicalIVRecipe>(*FoundWidenCanonicalIVUser);
2793     WideCanonicalIVs.push_back(WideCanonicalIV);
2794   }
2795 
2796   // Also include VPWidenIntOrFpInductionRecipes that represent a widened
2797   // version of the canonical induction.
2798   VPBasicBlock *HeaderVPBB = LoopRegion->getEntryBasicBlock();
2799   for (VPRecipeBase &Phi : HeaderVPBB->phis()) {
