2803   }
2804 
2805   // Walk users of wide canonical IVs and find the single compare of the form
2806   // (ICMP_ULE, WideCanonicalIV, backedge-taken-count).
2807   VPSingleDefRecipe *HeaderMask = nullptr;
2808   for (auto *Wide : WideCanonicalIVs) {
2809     for (VPUser *U : SmallVector<VPUser *>(Wide->users())) {
2810       auto *VPI = dyn_cast<VPInstruction>(U);
2811       if (!VPI || !vputils::isHeaderMask(VPI, Plan))
2812         continue;
2813 
2814       assert(VPI->getOperand(0) == Wide &&
2815              "WidenCanonicalIV must be the first operand of the compare");
2816       assert(!HeaderMask && "Multiple header masks found?");
