2824     VPlan &Plan, bool UseActiveLaneMaskForControlFlow,
2825     bool DataAndControlFlowWithoutRuntimeCheck) {
2826   assert((!DataAndControlFlowWithoutRuntimeCheck ||
2827           UseActiveLaneMaskForControlFlow) &&
2828          "DataAndControlFlowWithoutRuntimeCheck implies "
2829          "UseActiveLaneMaskForControlFlow");
2830 
2831   VPRegionBlock *LoopRegion = Plan.getVectorLoopRegion();
2832   auto *FoundWidenCanonicalIVUser = find_if(
2833       LoopRegion->getCanonicalIV()->users(), IsaPred<VPWidenCanonicalIVRecipe>);
2834   assert(FoundWidenCanonicalIVUser &&
2835          "Must have widened canonical IV when tail folding!");
2836   VPSingleDefRecipe *HeaderMask = findHeaderMask(Plan);
2837   auto *WideCanonicalIV =
2838       cast<VPWidenCanonicalIVRecipe>(*FoundWidenCanonicalIVUser);
2839   VPSingleDefRecipe *LaneMask;
2840   if (UseActiveLaneMaskForControlFlow) {
2841     LaneMask = addVPLaneMaskPhiAndUpdateExitBranch(
2842         Plan, DataAndControlFlowWithoutRuntimeCheck);
2843   } else {
2844     VPBuilder B = VPBuilder::getToInsertAfter(WideCanonicalIV);
2845     VPValue *ALMMultiplier = Plan.getOrAddLiveIn(
2846         ConstantInt::get(LoopRegion->getCanonicalIVType(), 1));
