2848         B.createNaryOp(VPInstruction::ActiveLaneMask,
2849                        {WideCanonicalIV, Plan.getTripCount(), ALMMultiplier},
2850                        nullptr, "active.lane.mask");
2851   }
2852 
2853   // Walk users of WideCanonicalIV and replace the header mask of the form
2854   // (ICMP_ULE, WideCanonicalIV, backedge-taken-count) with an active-lane-mask,
2855   // removing the old one to ensure there is always only a single header mask.
