3806 static Value *createBitOrPointerCast(IRBuilderBase &Builder, Value *V,
3807                                      VectorType *DstVTy, const DataLayout &DL) {
3808   // Verify that V is a vector type with same number of elements as DstVTy.
3809   auto VF = DstVTy->getElementCount();
3810   auto *SrcVecTy = cast<VectorType>(V->getType());
3811   assert(VF == SrcVecTy->getElementCount() && "Vector dimensions do not match");
3812   Type *SrcElemTy = SrcVecTy->getElementType();
3813   Type *DstElemTy = DstVTy->getElementType();
3814   assert((DL.getTypeSizeInBits(SrcElemTy) == DL.getTypeSizeInBits(DstElemTy)) &&
3815          "Vector elements must have same size");
3816 
3817   // Do a direct cast if element types are castable.
3818   if (CastInst::isBitOrNoopPointerCastable(SrcElemTy, DstElemTy, DL)) {
3819     return Builder.CreateBitOrPointerCast(V, DstVTy);
3820   }
3821   // V cannot be directly casted to desired vector type.
3822   // May happen when V is a floating point vector but DstVTy is a vector of
3823   // pointers or vice-versa. Handle this using a two-step bitcast using an
3824   // intermediate Integer type for the bitcast i.e. Ptr <-> Int <-> Float.
3825   assert((DstElemTy->isPointerTy() != SrcElemTy->isPointerTy()) &&
3826          "Only one type should be a pointer type");
3827   assert((DstElemTy->isFloatingPointTy() != SrcElemTy->isFloatingPointTy()) &&
3828          "Only one type should be a floating point type");
3829   Type *IntTy =
3830       IntegerType::getIntNTy(V->getContext(), DL.getTypeSizeInBits(SrcElemTy));
3831   auto *VecIntTy = VectorType::get(IntTy, VF);
3832   Value *CastVal = Builder.CreateBitOrPointerCast(V, VecIntTy);
3833   return Builder.CreateBitOrPointerCast(CastVal, DstVTy);
3834 }
