2523 void VPlanTransforms::truncateToMinimalBitwidths(
2524     VPlan &Plan, const MapVector<Instruction *, uint64_t> &MinBWs) {
2525   if (Plan.hasScalarVFOnly())
2526     return;
2527   // Keep track of created truncates, so they can be re-used. Note that we
2528   // cannot use RAUW after creating a new truncate, as this would could make
2529   // other uses have different types for their operands, making them invalidly
2530   // typed.
2531   DenseMap<VPValue *, VPWidenCastRecipe *> ProcessedTruncs;
2532   VPTypeAnalysis TypeInfo(Plan);
2533   VPBasicBlock *PH = Plan.getVectorPreheader();
2534   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2535            vp_depth_first_deep(Plan.getVectorLoopRegion()))) {
2536     for (VPRecipeBase &R : make_early_inc_range(*VPBB)) {
2537       if (!isa<VPWidenRecipe, VPWidenCastRecipe, VPReplicateRecipe,
2538                VPWidenLoadRecipe, VPWidenIntrinsicRecipe>(&R))
2539         continue;
2540 
2541       VPValue *ResultVPV = R.getVPSingleValue();
2542       auto *UI = cast_or_null<Instruction>(ResultVPV->getUnderlyingValue());
2543       unsigned NewResSizeInBits = MinBWs.lookup(UI);
2544       if (!NewResSizeInBits)
2545         continue;
2546 
2547       // If the value wasn't vectorized, we must maintain the original scalar
2548       // type. Skip those here, after incrementing NumProcessedRecipes. Also
2549       // skip casts which do not need to be handled explicitly here, as
2550       // redundant casts will be removed during recipe simplification.
2551       if (isa<VPReplicateRecipe, VPWidenCastRecipe>(&R))
2552         continue;
2553 
2554       Type *OldResTy = TypeInfo.inferScalarType(ResultVPV);
2555       unsigned OldResSizeInBits = OldResTy->getScalarSizeInBits();
2556       assert(OldResTy->isIntegerTy() && "only integer types supported");
2557       (void)OldResSizeInBits;
2558 
2559       auto *NewResTy = IntegerType::get(Plan.getContext(), NewResSizeInBits);
2560 
2561       // Any wrapping introduced by shrinking this operation shouldn't be
2562       // considered undefined behavior. So, we can't unconditionally copy
2563       // arithmetic wrapping flags to VPW.
2564       if (auto *VPW = dyn_cast<VPRecipeWithIRFlags>(&R))
2565         VPW->dropPoisonGeneratingFlags();
2566 
2567       if (OldResSizeInBits != NewResSizeInBits &&
2568           !match(&R, m_ICmp(m_VPValue(), m_VPValue()))) {
2569         // Extend result to original width.
2570         auto *Ext =
2571             new VPWidenCastRecipe(Instruction::ZExt, ResultVPV, OldResTy);
2572         Ext->insertAfter(&R);
2573         ResultVPV->replaceAllUsesWith(Ext);
2574         Ext->setOperand(0, ResultVPV);
2575         assert(OldResSizeInBits > NewResSizeInBits && "Nothing to shrink?");
2576       } else {
2577         assert(match(&R, m_ICmp(m_VPValue(), m_VPValue())) &&
2578                "Only ICmps should not need extending the result.");
2579       }
2580 
2581       assert(!isa<VPWidenStoreRecipe>(&R) && "stores cannot be narrowed");
2582       if (isa<VPWidenLoadRecipe, VPWidenIntrinsicRecipe>(&R))
2583         continue;
2584 
2585       // Shrink operands by introducing truncates as needed.
2586       unsigned StartIdx =
2587           match(&R, m_Select(m_VPValue(), m_VPValue(), m_VPValue())) ? 1 : 0;
2588       for (unsigned Idx = StartIdx; Idx != R.getNumOperands(); ++Idx) {
2589         auto *Op = R.getOperand(Idx);
2590         unsigned OpSizeInBits =
2591             TypeInfo.inferScalarType(Op)->getScalarSizeInBits();
2592         if (OpSizeInBits == NewResSizeInBits)
2593           continue;
2594         assert(OpSizeInBits > NewResSizeInBits && "nothing to truncate");
2595         auto [ProcessedIter, IterIsEmpty] = ProcessedTruncs.try_emplace(Op);
2596         if (!IterIsEmpty) {
2597           R.setOperand(Idx, ProcessedIter->second);
2598           continue;
2599         }
2600 
2601         VPBuilder Builder;
2602         if (Op->isLiveIn())
2603           Builder.setInsertPoint(PH);
2604         else
2605           Builder.setInsertPoint(&R);
2606         VPWidenCastRecipe *NewOp =
2607             Builder.createWidenCast(Instruction::Trunc, Op, NewResTy);
2608         ProcessedIter->second = NewOp;
2609         R.setOperand(Idx, NewOp);
