2616 void VPlanTransforms::removeBranchOnConst(VPlan &Plan) {
2617   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(
2618            vp_depth_first_shallow(Plan.getEntry()))) {
2619     VPValue *Cond;
2620     // Skip blocks that are not terminated by BranchOnCond.
2621     if (VPBB->empty() || !match(&VPBB->back(), m_BranchOnCond(m_VPValue(Cond))))
2622       continue;
2623 
2624     assert(VPBB->getNumSuccessors() == 2 &&
2625            "Two successors expected for BranchOnCond");
2626     unsigned RemovedIdx;
2627     if (match(Cond, m_True()))
2628       RemovedIdx = 1;
2629     else if (match(Cond, m_False()))
2630       RemovedIdx = 0;
2631     else
2632       continue;
2633 
2634     VPBasicBlock *RemovedSucc =
2635         cast<VPBasicBlock>(VPBB->getSuccessors()[RemovedIdx]);
2636     assert(count(RemovedSucc->getPredecessors(), VPBB) == 1 &&
2637            "There must be a single edge between VPBB and its successor");
2638     // Values coming from VPBB into phi recipes of RemoveSucc are removed from
2639     // these recipes.
2640     for (VPRecipeBase &R : RemovedSucc->phis())
2641       cast<VPPhiAccessors>(&R)->removeIncomingValueFor(VPBB);
2642 
2643     // Disconnect blocks and remove the terminator. RemovedSucc will be deleted
2644     // automatically on VPlan destruction if it becomes unreachable.
2645     VPBlockUtils::disconnectBlocks(VPBB, RemovedSucc);
2646     VPBB->back().eraseFromParent();
2647   }
