8251 VPRecipeBase *
8252 VPRecipeBuilder::tryToCreatePartialReduction(VPInstruction *Reduction,
8253                                              unsigned ScaleFactor) {
8254   assert(Reduction->getNumOperands() == 2 &&
8255          "Unexpected number of operands for partial reduction");
8256 
8257   VPValue *BinOp = Reduction->getOperand(0);
8258   VPValue *Accumulator = Reduction->getOperand(1);
8259   VPRecipeBase *BinOpRecipe = BinOp->getDefiningRecipe();
8260   if (isa<VPReductionPHIRecipe>(BinOpRecipe) ||
8261       (isa<VPReductionRecipe>(BinOpRecipe) &&
8262        cast<VPReductionRecipe>(BinOpRecipe)->isPartialReduction()))
8263     std::swap(BinOp, Accumulator);
8264 
8265   if (auto *RedPhiR = dyn_cast<VPReductionPHIRecipe>(Accumulator))
8266     RedPhiR->setVFScaleFactor(ScaleFactor);
8267 
8268   assert(ScaleFactor ==
8269              vputils::getVFScaleFactor(Accumulator->getDefiningRecipe()) &&
8270          "all accumulators in chain must have same scale factor");
8271 
8272   auto *ReductionI = Reduction->getUnderlyingInstr();
8273   if (Reduction->getOpcode() == Instruction::Sub) {
8274     SmallVector<VPValue *, 2> Ops;
8275     Ops.push_back(Plan.getConstantInt(ReductionI->getType(), 0));
8276     Ops.push_back(BinOp);
8277     BinOp = new VPWidenRecipe(*ReductionI, Ops, VPIRFlags(*ReductionI),
8278                               VPIRMetadata(), ReductionI->getDebugLoc());
8279     Builder.insert(BinOp->getDefiningRecipe());
8280   }
8281 
8282   VPValue *Cond = nullptr;
8283   if (CM.blockNeedsPredicationForAnyReason(ReductionI->getParent()))
8284     Cond = getBlockInMask(Builder.getInsertBlock());
8285 
8286   return new VPReductionRecipe(
8287       RecurKind::Add, FastMathFlags(), ReductionI, Accumulator, BinOp, Cond,
8288       RdxUnordered{/*VFScaleFactor=*/ScaleFactor}, ReductionI->getDebugLoc());
8289 }
