8291 void LoopVectorizationPlanner::buildVPlansWithVPRecipes(ElementCount MinVF,
8292                                                         ElementCount MaxVF) {
8293   if (ElementCount::isKnownGT(MinVF, MaxVF))
8294     return;
8295 
8296   assert(OrigLoop->isInnermost() && "Inner loop expected.");
8297 
8298   const LoopAccessInfo *LAI = Legal->getLAI();
8299   LoopVersioning LVer(*LAI, LAI->getRuntimePointerChecking()->getChecks(),
8300                       OrigLoop, LI, DT, PSE.getSE());
8301   if (!LAI->getRuntimePointerChecking()->getChecks().empty() &&
8302       !LAI->getRuntimePointerChecking()->getDiffChecks()) {
8303     // Only use noalias metadata when using memory checks guaranteeing no
8304     // overlap across all iterations.
8305     LVer.prepareNoAliasMetadata();
8306   }
8307 
8308   // Create initial base VPlan0, to serve as common starting point for all
8309   // candidates built later for specific VF ranges.
8310   auto VPlan0 = VPlanTransforms::buildVPlan0(
8311       OrigLoop, *LI, Legal->getWidestInductionType(),
8312       getDebugLocFromInstOrOperands(Legal->getPrimaryInduction()), PSE, &LVer);
8313 
8314   // Create recipes for header phis.
8315   VPlanTransforms::createHeaderPhiRecipes(
8316       *VPlan0, PSE, *OrigLoop, Legal->getInductionVars(),
8317       Legal->getReductionVars(), Legal->getFixedOrderRecurrences(),
8318       CM.getInLoopReductions(), Hints.allowReordering());
8319 
8320   auto MaxVFTimes2 = MaxVF * 2;
8321   for (ElementCount VF = MinVF; ElementCount::isKnownLT(VF, MaxVFTimes2);) {
8322     VFRange SubRange = {VF, MaxVFTimes2};
8323     if (auto Plan = tryToBuildVPlanWithVPRecipes(
8324             std::unique_ptr<VPlan>(VPlan0->duplicate()), SubRange, &LVer)) {
8325       // Now optimize the initial VPlan.
8326       VPlanTransforms::hoistPredicatedLoads(*Plan, PSE, OrigLoop);
8327       VPlanTransforms::sinkPredicatedStores(*Plan, PSE, OrigLoop);
8328       VPlanTransforms::runPass(VPlanTransforms::truncateToMinimalBitwidths,
8329                                *Plan, CM.getMinimalBitwidths());
8330       VPlanTransforms::runPass(VPlanTransforms::optimize, *Plan);
8331       // TODO: try to put it close to addActiveLaneMask().
8332       if (CM.foldTailWithEVL())
8333         VPlanTransforms::runPass(VPlanTransforms::addExplicitVectorLength,
8334                                  *Plan, CM.getMaxSafeElements());
8335       assert(verifyVPlanIsValid(*Plan) && "VPlan is invalid");
8336       VPlans.push_back(std::move(Plan));
8337     }
8338     VF = SubRange.End;
8339   }
8340 }
8341 
8342 VPlanPtr LoopVectorizationPlanner::tryToBuildVPlanWithVPRecipes(
8343     VPlanPtr Plan, VFRange &Range, LoopVersioning *LVer) {
8344 
8345   using namespace llvm::VPlanPatternMatch;
8346   SmallPtrSet<const InterleaveGroup<Instruction> *, 1> InterleaveGroups;
8347 
8348   // ---------------------------------------------------------------------------
8349   // Build initial VPlan: Scan the body of the loop in a topological order to
8350   // visit each basic block after having visited its predecessor basic blocks.
8351   // ---------------------------------------------------------------------------
8352 
8353   bool RequiresScalarEpilogueCheck =
8354       LoopVectorizationPlanner::getDecisionAndClampRange(
8355           [this](ElementCount VF) {
8356             return !CM.requiresScalarEpilogue(VF.isVector());
8357           },
8358           Range);
8359   VPlanTransforms::handleEarlyExits(*Plan, Legal->hasUncountableEarlyExit());
8360   VPlanTransforms::addMiddleCheck(*Plan, RequiresScalarEpilogueCheck,
8361                                   CM.foldTailByMasking());
8362 
8363   VPlanTransforms::createLoopRegions(*Plan);
8364 
8365   // Don't use getDecisionAndClampRange here, because we don't know the UF
8366   // so this function is better to be conservative, rather than to split
8367   // it up into different VPlans.
8368   // TODO: Consider using getDecisionAndClampRange here to split up VPlans.
8369   bool IVUpdateMayOverflow = false;
8370   for (ElementCount VF : Range)
8371     IVUpdateMayOverflow |= !isIndvarOverflowCheckKnownFalse(&CM, VF);
8372 
8373   TailFoldingStyle Style = CM.getTailFoldingStyle(IVUpdateMayOverflow);
8374   // Use NUW for the induction increment if we proved that it won't overflow in
8375   // the vector loop or when not folding the tail. In the later case, we know
8376   // that the canonical induction increment will not overflow as the vector trip
8377   // count is >= increment and a multiple of the increment.
8378   VPRegionBlock *LoopRegion = Plan->getVectorLoopRegion();
8379   bool HasNUW = !IVUpdateMayOverflow || Style == TailFoldingStyle::None;
8380   if (!HasNUW) {
8381     auto *IVInc =
8382         LoopRegion->getExitingBasicBlock()->getTerminator()->getOperand(0);
8383     assert(match(IVInc,
8384                  m_VPInstruction<Instruction::Add>(
8385                      m_Specific(LoopRegion->getCanonicalIV()), m_VPValue())) &&
8386            "Did not find the canonical IV increment");
8387     cast<VPRecipeWithIRFlags>(IVInc)->dropPoisonGeneratingFlags();
8388   }
8389 
8390   // ---------------------------------------------------------------------------
8391   // Pre-construction: record ingredients whose recipes we'll need to further
8392   // process after constructing the initial VPlan.
8393   // ---------------------------------------------------------------------------
8394 
8395   // For each interleave group which is relevant for this (possibly trimmed)
8396   // Range, add it to the set of groups to be later applied to the VPlan and add
8397   // placeholders for its members' Recipes which we'll be replacing with a
8398   // single VPInterleaveRecipe.
8399   for (InterleaveGroup<Instruction> *IG : IAI.getInterleaveGroups()) {
8400     auto ApplyIG = [IG, this](ElementCount VF) -> bool {
8401       bool Result = (VF.isVector() && // Query is illegal for VF == 1
8402                      CM.getWideningDecision(IG->getInsertPos(), VF) ==
8403                          LoopVectorizationCostModel::CM_Interleave);
8404       // For scalable vectors, the interleave factors must be <= 8 since we
8405       // require the (de)interleaveN intrinsics instead of shufflevectors.
8406       assert((!Result || !VF.isScalable() || IG->getFactor() <= 8) &&
8407              "Unsupported interleave factor for scalable vectors");
8408       return Result;
8409     };
8410     if (!getDecisionAndClampRange(ApplyIG, Range))
8411       continue;
8412     InterleaveGroups.insert(IG);
8413   }
8414 
8415   // ---------------------------------------------------------------------------
8416   // Predicate and linearize the top-level loop region.
8417   // ---------------------------------------------------------------------------
8418   auto BlockMaskCache = VPlanTransforms::introduceMasksAndLinearize(
8419       *Plan, CM.foldTailByMasking());
8420 
8421   // ---------------------------------------------------------------------------
8422   // Construct wide recipes and apply predication for original scalar
8423   // VPInstructions in the loop.
8424   // ---------------------------------------------------------------------------
8425   VPRecipeBuilder RecipeBuilder(*Plan, OrigLoop, TLI, &TTI, Legal, CM, Builder,
8426                                 BlockMaskCache);
8427   // TODO: Handle partial reductions with EVL tail folding.
8428   if (!CM.foldTailWithEVL())
8429     RecipeBuilder.collectScaledReductions(Range);
8430 
8431   // Scan the body of the loop in a topological order to visit each basic block
8432   // after having visited its predecessor basic blocks.
8433   VPBasicBlock *HeaderVPBB = LoopRegion->getEntryBasicBlock();
8434   ReversePostOrderTraversal<VPBlockShallowTraversalWrapper<VPBlockBase *>> RPOT(
8435       HeaderVPBB);
8436 
8437   auto *MiddleVPBB = Plan->getMiddleBlock();
8438   VPBasicBlock::iterator MBIP = MiddleVPBB->getFirstNonPhi();
8439   // Mapping from VPValues in the initial plan to their widened VPValues. Needed
8440   // temporarily to update created block masks.
8441   DenseMap<VPValue *, VPValue *> Old2New;
8442 
8443   // Collect blocks that need predication for in-loop reduction recipes.
8444   DenseSet<BasicBlock *> BlocksNeedingPredication;
8445   for (BasicBlock *BB : OrigLoop->blocks())
8446     if (CM.blockNeedsPredicationForAnyReason(BB))
8447       BlocksNeedingPredication.insert(BB);
8448 
8449   VPlanTransforms::createInLoopReductionRecipes(
8450       *Plan, BlockMaskCache, BlocksNeedingPredication, Range.Start);
8451 
8452   // Now process all other blocks and instructions.
8453   for (VPBasicBlock *VPBB : VPBlockUtils::blocksOnly<VPBasicBlock>(RPOT)) {
8454     // Convert input VPInstructions to widened recipes.
8455     for (VPRecipeBase &R : make_early_inc_range(
8456              make_range(VPBB->getFirstNonPhi(), VPBB->end()))) {
8457       // Skip recipes that do not need transforming.
8458       if (isa<VPWidenCanonicalIVRecipe, VPBlendRecipe, VPReductionRecipe>(&R))
8459         continue;
8460       auto *VPI = cast<VPInstruction>(&R);
8461       if (!VPI->getUnderlyingValue())
8462         continue;
8463 
8464       // TODO: Gradually replace uses of underlying instruction by analyses on
8465       // VPlan. Migrate code relying on the underlying instruction from VPlan0
8466       // to construct recipes below to not use the underlying instruction.
8467       Instruction *Instr = cast<Instruction>(VPI->getUnderlyingValue());
8468       Builder.setInsertPoint(VPI);
8469 
8470       // The stores with invariant address inside the loop will be deleted, and
8471       // in the exit block, a uniform store recipe will be created for the final
8472       // invariant store of the reduction.
8473       StoreInst *SI;
8474       if ((SI = dyn_cast<StoreInst>(Instr)) &&
8475           Legal->isInvariantAddressOfReduction(SI->getPointerOperand())) {
8476         // Only create recipe for the final invariant store of the reduction.
8477         if (Legal->isInvariantStoreOfReduction(SI)) {
8478           auto *Recipe = new VPReplicateRecipe(
8479               SI, R.operands(), true /* IsUniform */, nullptr /*Mask*/, *VPI,
8480               *VPI, VPI->getDebugLoc());
8481           Recipe->insertBefore(*MiddleVPBB, MBIP);
8482         }
8483         R.eraseFromParent();
8484         continue;
8485       }
